<?php
if (!function_exists('hr_t')) {
  function hr_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('hr_h')) {
  function hr_h($key, $fallback = '') { return htmlspecialchars((string) hr_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('hr_js')) {
  function hr_js($key, $fallback = '') { return json_encode(hr_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
if (session_status() === PHP_SESSION_NONE) session_start();
include "../../inc/config.php";
session_check_json();
function edd_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function edd_label($s,$kind='status'){$map=$kind==='verify'?array('PENDING'=>'warning','VERIFIED'=>'success','REJECTED'=>'danger'):array('ACTIVE'=>'success','INACTIVE'=>'warning','EXPIRED'=>'danger','ARCHIVED'=>'default');$c=isset($map[$s])?$map[$s]:'default';return '<span class="label label-'.$c.'">'.edd_h($s).'</span>';}
$draw=isset($_POST['draw'])?(int)$_POST['draw']:1;$start=isset($_POST['start'])?max(0,(int)$_POST['start']):0;$length=isset($_POST['length'])?(int)$_POST['length']:25;if($length<=0||$length>500)$length=25;
$from=isset($_POST['tgl_awal'])&&$_POST['tgl_awal']!==''?$_POST['tgl_awal']:date('Y-01-01');$to=isset($_POST['tgl_akhir'])&&$_POST['tgl_akhir']!==''?$_POST['tgl_akhir']:'9999-12-31';$type=isset($_POST['document_type'])?trim($_POST['document_type']):'';$cat=isset($_POST['document_category'])?trim($_POST['document_category']):'';$verify=isset($_POST['verification_status'])?trim($_POST['verification_status']):'';$status=isset($_POST['status'])?trim($_POST['status']):'';$exp=isset($_POST['expiring_soon'])?trim($_POST['expiring_soon']):'';$kw=isset($_POST['keyword'])?trim($_POST['keyword']):'';
$w=" WHERE doc.effective_from<=? AND doc.effective_to>=? ";$p=array($to,$from);if($type!==''){$w.=" AND doc.document_type=? ";$p[]=$type;}if($cat!==''){$w.=" AND doc.document_category=? ";$p[]=$cat;}if($verify!==''){$w.=" AND doc.verification_status=? ";$p[]=$verify;}if($status!==''){$w.=" AND doc.status=? ";$p[]=$status;}if($exp==='Y')$w.=" AND doc.expiry_date IS NOT NULL AND doc.expiry_date BETWEEN CURDATE() AND DATE_ADD(CURDATE(),INTERVAL 90 DAY) ";if($kw!==''){$like='%'.$kw.'%';$w.=" AND (doc.document_no LIKE ? OR doc.document_title LIKE ? OR doc.document_number LIKE ? OR e.employee_no LIKE ? OR e.full_name LIKE ? OR doc.file_name LIKE ?) ";array_push($p,$like,$like,$like,$like,$like,$like);}
$kpi=$db->fetch("SELECT COUNT(*) total,SUM(status='ACTIVE') active,SUM(verification_status='PENDING') pending,SUM(confidential='Y') confidential,SUM(expiry_date IS NOT NULL AND expiry_date BETWEEN CURDATE() AND DATE_ADD(CURDATE(),INTERVAL 90 DAY)) expiring_soon FROM erp_employee_document");
$cnt=$db->fetch("SELECT COUNT(*) jml FROM erp_employee_document doc JOIN erp_employee_master e ON e.id=doc.employee_id $w",$p);$total=$cnt?(int)$cnt->jml:0;
$orderMap=array(2=>'doc.document_no',3=>'e.employee_no',4=>'doc.document_type',5=>'doc.document_category',6=>'doc.document_title',7=>'doc.expiry_date',8=>'doc.verification_status',9=>'doc.status',10=>'doc.updated_at');$orderBy='e.employee_no,doc.document_category,doc.document_type';if(isset($_POST['order'][0]['column'])){$col=(int)$_POST['order'][0]['column'];$dir=(isset($_POST['order'][0]['dir'])&&strtolower($_POST['order'][0]['dir'])==='desc')?'DESC':'ASC';if(isset($orderMap[$col]))$orderBy=$orderMap[$col].' '.$dir;}
$rows=$db->query("SELECT doc.*,e.employee_no,e.full_name,e.department_code,d.nm_dept,j.job_title_code,j.job_title_name,v.employee_no verifier_no,v.full_name verifier_name FROM erp_employee_document doc JOIN erp_employee_master e ON e.id=doc.employee_id LEFT JOIN dept d ON d.kd_dept=e.department_code LEFT JOIN erp_job_title j ON j.id=e.job_title_id LEFT JOIN erp_employee_master v ON v.id=doc.verified_by_employee_id $w ORDER BY $orderBy LIMIT $start,$length",$p);
$data=array();$no=$start+1;foreach($rows as $r){$next=$r->status==='ACTIVE'?'ARCHIVED':'ACTIVE';$btn=$r->status==='ACTIVE'?'warning':'success';$icon=$r->status==='ACTIVE'?'fa-archive':'fa-check';$act='<div class="ed-action"><button class="btn btn-info btn-xs btn-ed-detail" data-id="'.(int)$r->id.'" title="'.hr_h('common_detail', 'Detail').'"><i class="fa fa-eye"></i></button> <button class="btn btn-primary btn-xs btn-ed-edit" data-id="'.(int)$r->id.'" title="'.hr_h('common_edit', 'Edit').'"><i class="fa fa-pencil"></i></button> <button class="btn btn-'.$btn.' btn-xs btn-ed-status" data-id="'.(int)$r->id.'" data-status="'.$next.'" title="'.$next.'"><i class="fa '.$icon.'"></i></button> <button class="btn btn-danger btn-xs btn-ed-delete" data-id="'.(int)$r->id.'" data-no="'.edd_h($r->document_no).'" title="'.hr_h('common_delete', 'Delete').'"><i class="fa fa-trash"></i></button></div>';
  $data[]=array($no++,$act,'<strong>'.edd_h($r->document_no).'</strong><br><small>SAP: '.edd_h($r->sap_reference?:'-').'</small>','<strong>'.edd_h($r->employee_no).'</strong><br><small>'.edd_h($r->full_name).'</small><br><small>'.edd_h($r->department_code?:'-').' '.edd_h($r->nm_dept?:'').'</small>','<strong>'.edd_h($r->document_type).'</strong><br><small>'.edd_h($r->document_category).'</small>','<strong>'.edd_h($r->document_title).'</strong><br><small>No: '.edd_h($r->document_number?:'-').'</small>','Issue: '.edd_h($r->issue_date?:'-').'<br><small>Expiry: '.edd_h($r->expiry_date?:'-').'</small>',edd_h($r->file_name?:'-').'<br><small>'.edd_h($r->file_type?:'-').' | Confidential: '.edd_h($r->confidential).'</small>',edd_label($r->verification_status,'verify').'<br><small>'.edd_h($r->verifier_no?:'-').'</small>',edd_label($r->status),edd_h($r->updated_by?:$r->created_by?:'-').'<br><small>'.edd_h($r->updated_at?:$r->created_at).'</small>');}
header('Content-Type: application/json; charset=utf-8');echo json_encode(array('draw'=>$draw,'recordsTotal'=>$total,'recordsFiltered'=>$total,'data'=>$data,'kpi'=>array('total'=>$kpi?(int)$kpi->total:0,'active'=>$kpi?(int)$kpi->active:0,'pending'=>$kpi?(int)$kpi->pending:0,'confidential'=>$kpi?(int)$kpi->confidential:0,'expiring_soon'=>$kpi?(int)$kpi->expiring_soon:0)));
?>
